import{_ as e,o,c as n,a0 as s}from"./chunks/framework.BjpW4enL.js";const i="/assets/dashboard_mockup.dTpCvh9X.jpg",t="/assets/scanner_mockup.D1dnXV8X.jpg",r="/assets/whatsapp_integration_mockup.DxNuxQPH.jpg",_=JSON.parse('{"title":"Integração IntraClinica NG & NEXUS","description":"","frontmatter":{},"headers":[],"relativePath":"20_Arquitetura/concepts/intraclinica-integration.md","filePath":"20_Arquitetura/concepts/intraclinica-integration.md","lastUpdated":1783623176000}'),d={name:"20_Arquitetura/concepts/intraclinica-integration.md"};function c(l,a,p,m,u,g){return o(),n("div",null,[...a[0]||(a[0]=[s('<h1 id="integracao-intraclinica-ng-nexus" tabindex="-1">Integração IntraClinica NG &amp; NEXUS <a class="header-anchor" href="#integracao-intraclinica-ng-nexus" aria-label="Permalink to &quot;Integração IntraClinica NG &amp; NEXUS&quot;">​</a></h1><p><strong>Tipo:</strong> MOC 2-simplex — especificação técnica de integração do MVP</p><p>Este documento mapeia como os módulos do MVP do <strong>IntraClinica NG</strong> (WhatsApp, Triagem Assíncrona, Rastreabilidade de Insumos e Acompanhamento) utilizam a engine semântica e relacional do <strong>NEXUS</strong>.</p><p><img src="'+i+'" alt="Painel Unificado de Intenção Médica"></p><h2 id="_1-rastreabilidade-de-insumos-controle-de-estoque-ativo" tabindex="-1">1. Rastreabilidade de Insumos (Controle de Estoque Ativo) <a class="header-anchor" href="#_1-rastreabilidade-de-insumos-controle-de-estoque-ativo" aria-label="Permalink to &quot;1. Rastreabilidade de Insumos (Controle de Estoque Ativo)&quot;">​</a></h2><p>Para evitar desvios e furos em insumos de estética de alto valor, a baixa de estoque é um invariante acoplado ao início do atendimento clínico no T4.</p><p><img src="'+t+'" alt="Modal de Escaneamento de Insumo por Etiqueta"></p><h3 id="fluxo-de-validacao" tabindex="-1">Fluxo de Validação <a class="header-anchor" href="#fluxo-de-validacao" aria-label="Permalink to &quot;Fluxo de Validação&quot;">​</a></h3><ul><li><strong>Entrada (Intenção):</strong> Prontuário solicita início de procedimento.</li><li><strong>T4 Query:</strong> O motor busca os insumos obrigatórios associados ao procedimento na tabela <code>abstractions</code>.</li><li><strong>Validação Física:</strong> A UI renderiza a tela de scanner de código de barras. O bipe do frasco associa o <code>lote_id</code> do insumo ao nó de prontuário e dispara o evento de baixa no banco.</li></ul><h2 id="_2-anamnese-assincrona-whatsapp-ingestion" tabindex="-1">2. Anamnese Assíncrona (WhatsApp Ingestion) <a class="header-anchor" href="#_2-anamnese-assincrona-whatsapp-ingestion" aria-label="Permalink to &quot;2. Anamnese Assíncrona (WhatsApp Ingestion)&quot;">​</a></h2><p>A coleta de dados pré-consulta do paciente é processada de forma assíncrona e local.</p><p><img src="'+r+`" alt="Visão Integrada de Triagem do WhatsApp para IA Clínica"></p><h3 id="pipeline-de-ingestao" tabindex="-1">Pipeline de Ingestão <a class="header-anchor" href="#pipeline-de-ingestao" aria-label="Permalink to &quot;Pipeline de Ingestão&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[WhatsApp API] ──&gt; [ingest_queue (Postgres)]</span></span>
<span class="line"><span>                        │</span></span>
<span class="line"><span>                        ▼</span></span>
<span class="line"><span>           [NEXUS Coordinator (L1/L2)]</span></span>
<span class="line"><span>                        │</span></span>
<span class="line"><span>                        ▼</span></span>
<span class="line"><span>          [Extração de Entidades Clínicas]</span></span>
<span class="line"><span>                        │</span></span>
<span class="line"><span>                        ▼</span></span>
<span class="line"><span>    [Aresta &#39;part_of&#39; criada ligando ao Paciente]</span></span></code></pre></div><p>O texto livre coletado no celular do paciente passa pelo modelo local (<code>qwen2.5-coder:nexus</code>), gerando um sumário clínico formatado na tabela de <code>abstractions</code> antes da chegada do paciente ao consultório.</p><h2 id="_3-acompanhamento-medico-passivo" tabindex="-1">3. Acompanhamento Médico Passivo <a class="header-anchor" href="#_3-acompanhamento-medico-passivo" aria-label="Permalink to &quot;3. Acompanhamento Médico Passivo&quot;">​</a></h2><p>Detecção de desvios clínicos entre consultas usando o grafo estigmérgico do T4.</p><h3 id="mecanismo-de-alerta" tabindex="-1">Mecanismo de Alerta <a class="header-anchor" href="#mecanismo-de-alerta" aria-label="Permalink to &quot;Mecanismo de Alerta&quot;">​</a></h3><ul><li>Dados informados pelo paciente pós-consulta alimentam a tabela <code>blobs</code>.</li><li>O decay temporal do T4 reduz a energia das arestas do prontuário antigo se não houver novas informações.</li><li>Caso o processamento L2 detecte palavras-chave de risco (sintomas de complicação), uma aresta temporária de alta energia (<code>semantic_bridge</code>) é criada, disparando um alerta visual imediato no dashboard da médica.</li></ul>`,19)])])}const b=e(d,[["render",c]]);export{_ as __pageData,b as default};
